/**
 * Minimal but functional Markdown-to-HTML parser.
 * Handles block-level and inline parsing with proper nesting.
 * ES module — `export function marked(text)`.
 */

// ── Helpers ──────────────────────────────────────────────────

function escapeHtml(str) {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// ── Inline parsing ───────────────────────────────────────────

function parseInline(text) {
  let out = '';
  let i = 0;
  const len = text.length;

  while (i < len) {
    // Escaped character
    if (text[i] === '\\' && i + 1 < len) {
      out += escapeHtml(text[i + 1]);
      i += 2;
      continue;
    }

    // Image: ![alt](src)
    if (text[i] === '!' && text[i + 1] === '[') {
      const altEnd = text.indexOf(']', i + 2);
      if (altEnd !== -1 && text[altEnd + 1] === '(') {
        const srcEnd = text.indexOf(')', altEnd + 2);
        if (srcEnd !== -1) {
          const alt = escapeHtml(text.slice(i + 2, altEnd));
          const src = escapeHtml(text.slice(altEnd + 2, srcEnd));
          out += `<img src="${src}" alt="${alt}">`;
          i = srcEnd + 1;
          continue;
        }
      }
    }

    // Link: [text](url)
    if (text[i] === '[') {
      const textEnd = text.indexOf(']', i + 1);
      if (textEnd !== -1 && text[textEnd + 1] === '(') {
        const urlEnd = text.indexOf(')', textEnd + 2);
        if (urlEnd !== -1) {
          const linkText = parseInline(text.slice(i + 1, textEnd));
          const url = escapeHtml(text.slice(textEnd + 2, urlEnd));
          out += `<a href="${url}">${linkText}</a>`;
          i = urlEnd + 1;
          continue;
        }
      }
    }

    // Code span: `code` or ``code``
    if (text[i] === '`') {
      // count opening backticks
      let ticks = 0;
      let j = i;
      while (j < len && text[j] === '`') { ticks++; j++; }
      // find matching closing backticks
      const closer = text.indexOf('`'.repeat(ticks), j);
      if (closer !== -1) {
        const code = escapeHtml(text.slice(j, closer).replace(/^ | $/g, ''));
        out += `<code>${code}</code>`;
        i = closer + ticks;
        continue;
      }
      // no closing — emit literal
      out += escapeHtml('`'.repeat(ticks));
      i = j;
      continue;
    }

    // Strikethrough: ~~text~~
    if (text[i] === '~' && text[i + 1] === '~') {
      const end = text.indexOf('~~', i + 2);
      if (end !== -1) {
        out += `<del>${parseInline(text.slice(i + 2, end))}</del>`;
        i = end + 2;
        continue;
      }
    }

    // Bold + italic: ***text*** or ___text___
    if ((text[i] === '*' || text[i] === '_') && text[i + 1] === text[i] && text[i + 2] === text[i]) {
      const ch = text[i];
      const end = text.indexOf(ch + ch + ch, i + 3);
      if (end !== -1) {
        out += `<strong><em>${parseInline(text.slice(i + 3, end))}</em></strong>`;
        i = end + 3;
        continue;
      }
    }

    // Bold: **text** or __text__
    if ((text[i] === '*' || text[i] === '_') && text[i + 1] === text[i]) {
      const ch = text[i];
      const end = findClosingPair(text, ch + ch, i + 2);
      if (end !== -1) {
        out += `<strong>${parseInline(text.slice(i + 2, end))}</strong>`;
        i = end + 2;
        continue;
      }
    }

    // Italic: *text* or _text_
    if (text[i] === '*' || text[i] === '_') {
      const ch = text[i];
      const end = findClosingSingle(text, ch, i + 1);
      if (end !== -1) {
        out += `<em>${parseInline(text.slice(i + 1, end))}</em>`;
        i = end + 1;
        continue;
      }
    }

    // Line break: two trailing spaces + newline or explicit <br>
    if (text[i] === ' ' && text[i + 1] === ' ' && text[i + 2] === '\n') {
      out += '<br>';
      i += 3;
      continue;
    }

    // Default: emit escaped character
    out += escapeHtml(text[i]);
    i++;
  }

  return out;
}

function findClosingPair(text, pair, start) {
  const idx = text.indexOf(pair, start);
  // ensure the match isn't immediately (empty content)
  if (idx > start) return idx;
  return -1;
}

function findClosingSingle(text, ch, start) {
  for (let j = start; j < text.length; j++) {
    if (text[j] === ch && (ch !== '_' || j + 1 >= text.length || /\W/.test(text[j + 1]))) {
      if (j > start) return j;
    }
  }
  return -1;
}


// ── Block parsing ────────────────────────────────────────────

/**
 * Parse markdown text into an array of block tokens.
 * Each token is { type, ... } with type-specific fields.
 */
function tokenize(src) {
  const tokens = [];
  const lines = src.split('\n');
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    // ── Fenced code block ───────────────────────
    const fenceMatch = line.match(/^(`{3,}|~{3,})(\w*)\s*$/);
    if (fenceMatch) {
      const fence = fenceMatch[1];
      const lang = fenceMatch[2] || '';
      const codeLines = [];
      i++;
      while (i < lines.length) {
        if (lines[i].startsWith(fence) && lines[i].trim() === fence) {
          i++;
          break;
        }
        codeLines.push(lines[i]);
        i++;
      }
      tokens.push({ type: 'code', lang, text: codeLines.join('\n') });
      continue;
    }

    // ── Horizontal rule: ---, ***, ___  (3+ chars, possibly with spaces)
    if (/^(\s{0,3})([-*_])\s*(\2\s*){2,}$/.test(line)) {
      tokens.push({ type: 'hr' });
      i++;
      continue;
    }

    // ── ATX heading: # ... ######
    const headingMatch = line.match(/^(#{1,6})\s+(.+?)(?:\s+#+)?\s*$/);
    if (headingMatch) {
      tokens.push({ type: 'heading', depth: headingMatch[1].length, text: headingMatch[2] });
      i++;
      continue;
    }

    // ── Table: starts with |...|, next line is separator |---|
    if (/^\|(.+)\|$/.test(line.trim()) && i + 1 < lines.length && /^\|[\s:]*-+/.test(lines[i + 1].trim())) {
      const headerCells = parseTableRow(line);
      const sepLine = lines[i + 1];
      const aligns = parseTableAlign(sepLine);
      const rows = [];
      i += 2;
      while (i < lines.length && /^\|(.+)\|$/.test(lines[i].trim())) {
        rows.push(parseTableRow(lines[i]));
        i++;
      }
      tokens.push({ type: 'table', header: headerCells, align: aligns, rows });
      continue;
    }

    // ── Blockquote
    if (/^>\s?/.test(line)) {
      const quoteLines = [];
      while (i < lines.length && /^>\s?/.test(lines[i])) {
        quoteLines.push(lines[i].replace(/^>\s?/, ''));
        i++;
      }
      // Recursively parse inner content
      tokens.push({ type: 'blockquote', tokens: tokenize(quoteLines.join('\n')) });
      continue;
    }

    // ── Unordered list: -, *, +
    if (/^(\s{0,3})([-*+])\s+/.test(line)) {
      const items = parseListItems(lines, i, 'ul');
      tokens.push({ type: 'list', ordered: false, items: items.items });
      i = items.end;
      continue;
    }

    // ── Ordered list: 1. 2. etc
    if (/^(\s{0,3})(\d+)[.)]\s+/.test(line)) {
      const items = parseListItems(lines, i, 'ol');
      tokens.push({ type: 'list', ordered: true, items: items.items });
      i = items.end;
      continue;
    }

    // ── Blank line
    if (line.trim() === '') {
      i++;
      continue;
    }

    // ── Paragraph: collect lines until blank or block element
    const paraLines = [];
    while (i < lines.length) {
      const l = lines[i];
      if (l.trim() === '') break;
      if (/^(`{3,}|~{3,})/.test(l)) break;
      if (/^#{1,6}\s+/.test(l)) break;
      if (/^(\s{0,3})([-*_])\s*(\2\s*){2,}$/.test(l)) break;
      if (/^>\s?/.test(l)) break;
      if (/^(\s{0,3})([-*+])\s+/.test(l)) break;
      if (/^(\s{0,3})(\d+)[.)]\s+/.test(l)) break;
      if (/^\|(.+)\|$/.test(l.trim()) && i + 1 < lines.length && /^\|[\s:]*-+/.test(lines[i + 1]?.trim() || '')) break;
      paraLines.push(l);
      i++;
    }
    if (paraLines.length) {
      tokens.push({ type: 'paragraph', text: paraLines.join('\n') });
    }
  }

  return tokens;
}


// ── List parsing ─────────────────────────────────────────────

function parseListItems(lines, start, listType) {
  const items = [];
  let i = start;
  const bulletRe = listType === 'ul' ? /^(\s*)([-*+])\s+(.*)$/ : /^(\s*)(\d+)[.)]\s+(.*)$/;
  // Determine the base indent level
  const baseMatch = lines[start].match(bulletRe);
  if (!baseMatch) return { items: [], end: start + 1 };
  const baseIndent = baseMatch[1].length;

  while (i < lines.length) {
    const m = lines[i].match(bulletRe);
    if (m && m[1].length === baseIndent) {
      // New item at this level
      const itemLines = [m[3]];
      i++;

      // Continuation lines: either indented or sub-list
      while (i < lines.length) {
        const nextLine = lines[i];
        if (nextLine.trim() === '') {
          // Blank line may be part of list item if next line is indented
          if (i + 1 < lines.length && /^\s{2,}/.test(lines[i + 1])) {
            itemLines.push('');
            i++;
            continue;
          }
          break;
        }
        // Check if next item at same level
        const nm = nextLine.match(bulletRe);
        if (nm && nm[1].length === baseIndent) break;
        // Check if different list type at same level
        const otherBullet = listType === 'ul' ? /^(\s*)(\d+)[.)]\s+/ : /^(\s*)([-*+])\s+/;
        const om = nextLine.match(otherBullet);
        if (om && om[1].length === baseIndent) break;
        // Indented continuation or sub-list
        if (/^\s+/.test(nextLine) || /^(\s*)([-*+]|\d+[.)])\s+/.test(nextLine)) {
          itemLines.push(nextLine);
          i++;
          continue;
        }
        break;
      }

      items.push(itemLines.join('\n'));
    } else {
      break;
    }
  }

  return { items, end: i };
}


// ── Table parsing ────────────────────────────────────────────

function parseTableRow(line) {
  return line.trim().replace(/^\|/, '').replace(/\|$/, '').split('|').map(c => c.trim());
}

function parseTableAlign(line) {
  return line.trim().replace(/^\|/, '').replace(/\|$/, '').split('|').map(c => {
    c = c.trim();
    if (c.startsWith(':') && c.endsWith(':')) return 'center';
    if (c.endsWith(':')) return 'right';
    return 'left';
  });
}


// ── Render tokens to HTML ────────────────────────────────────

function renderTokens(tokens) {
  let html = '';
  for (const tok of tokens) {
    switch (tok.type) {
      case 'heading':
        html += `<h${tok.depth}>${parseInline(tok.text)}</h${tok.depth}>\n`;
        break;

      case 'paragraph':
        html += `<p>${parseInline(tok.text)}</p>\n`;
        break;

      case 'code':
        html += `<pre><code${tok.lang ? ` class="language-${escapeHtml(tok.lang)}"` : ''}>${escapeHtml(tok.text)}</code></pre>\n`;
        break;

      case 'hr':
        html += '<hr>\n';
        break;

      case 'blockquote':
        html += `<blockquote>${renderTokens(tok.tokens)}</blockquote>\n`;
        break;

      case 'list':
        html += renderList(tok);
        break;

      case 'table':
        html += renderTable(tok);
        break;

      default:
        break;
    }
  }
  return html;
}

function renderList(tok) {
  const tag = tok.ordered ? 'ol' : 'ul';
  let html = `<${tag}>\n`;
  for (const item of tok.items) {
    html += renderListItem(item);
  }
  html += `</${tag}>\n`;
  return html;
}

function renderListItem(text) {
  // Check for task list: - [x] or - [ ]
  const taskMatch = text.match(/^\[([ xX])\]\s+([\s\S]*)$/);
  if (taskMatch) {
    const checked = taskMatch[1] !== ' ' ? ' checked disabled' : ' disabled';
    const inner = renderListItemContent(taskMatch[2]);
    return `<li><input type="checkbox"${checked}>${inner}</li>\n`;
  }

  const inner = renderListItemContent(text);
  return `<li>${inner}</li>\n`;
}

function renderListItemContent(text) {
  // Check for nested list within item
  const lines = text.split('\n');
  if (lines.length === 1) {
    return parseInline(text);
  }

  // First line is the item text
  let result = parseInline(lines[0]);

  // Remaining lines may form a sub-list
  const subLines = lines.slice(1).map(l => {
    // Remove up to 2 spaces of leading indent (normalization for nesting)
    if (l.startsWith('  ')) return l.slice(2);
    if (l.startsWith('\t')) return l.slice(1);
    return l;
  });

  const subSrc = subLines.join('\n');
  const subTokens = tokenize(subSrc);
  if (subTokens.length) {
    result += renderTokens(subTokens);
  }

  return result;
}

function renderTable(tok) {
  let html = '<table>\n<thead>\n<tr>\n';
  for (let c = 0; c < tok.header.length; c++) {
    const align = tok.align[c] ? ` style="text-align:${tok.align[c]}"` : '';
    html += `<th${align}>${parseInline(tok.header[c])}</th>\n`;
  }
  html += '</tr>\n</thead>\n';

  if (tok.rows.length) {
    html += '<tbody>\n';
    for (const row of tok.rows) {
      html += '<tr>\n';
      for (let c = 0; c < tok.header.length; c++) {
        const align = tok.align[c] ? ` style="text-align:${tok.align[c]}"` : '';
        const cell = row[c] !== undefined ? parseInline(row[c]) : '';
        html += `<td${align}>${cell}</td>\n`;
      }
      html += '</tr>\n';
    }
    html += '</tbody>\n';
  }

  html += '</table>\n';
  return html;
}


// ── Public API ───────────────────────────────────────────────

export function marked(text) {
  if (!text) return '';
  // Normalize line endings
  const src = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  const tokens = tokenize(src);
  return renderTokens(tokens);
}
